var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DEMON_VELES_NPC_PRIEST","text":{"KOREA":"우리는 황금나무의 예언을 받드는 낙원의 사도-","JPN":"我らは黄金の木の予言に従う楽園の使徒……","ENG":"We are the Apostles of the Promised Land who serve the prophecy of the Golden Tree.","TWN":"我們是守護黃金樹預言的樂園使徒—"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_PRIEST","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DEMON_VELES_NPC_PRIEST","text":{"KOREA":"하늘이 갈라지고 어둠이 내려앉아도, 우리는 변함없이 기도하리라.","JPN":"天が裂かれ暗闇が訪れるとしても、我らは変わらず祈ろう。","ENG":"Even if the heavens split apart and darkness descends, we shall pray without faltering.","TWN":"即使天空分裂、黑暗降臨，我們仍會祈禱。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_PRIEST","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DEMON_VELES_NPC_PRIEST","text":{"KOREA":"이 땅에 천사가 내려오고, 노랫소리가 울려 퍼지면, 우리의 정적 또한 심판 받을 지니.","JPN":"この地に天使が降り立ち、歌声が響けば、我らの政敵もまた審判されよう。","ENG":"When angels descend upon this land and song echoes through the air, our foe shall face judgment as well.","TWN":"當天使降臨這片土地、歌聲響起時，我們的寂靜也將受到審判。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_PRIEST","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DEMON_VELES_NPC_PRIEST","text":{"KOREA":"우리가 비원을 이루는 그날- 가을 끝무렵의 침묵 속에서, 비로소 낙원은 완성되리라.","JPN":"我らの悲願が叶うその日……晩秋の沈黙の中で、ついに楽園は完成されるだろう。","ENG":"On the day our wish is fulfilled. Within the silence at the end of autumn, the Promised Land shall at last be complete.","TWN":"在我們願望實現的那一天—樂園終將在秋末的沉默中完成。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_PRIEST","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"영겁 끝에 맞닥뜨리게 될 첫눈을 맞으며-","JPN":"永劫の果てに迎える初雪とともに……","ENG":"As we welcome the first snowfall we will encounter at the end of eternity...","TWN":"在永恆之終迎來的第一場雪—"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_PRIEST","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"낙원의 약속은, 그렇게 이루어지리라.","JPN":"楽園の約束は、そうして叶うだろう。","ENG":"Thus shall the promise of the Promised Land be fulfilled.","TWN":"將如此實現樂園的承諾。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_PRIEST","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DEMON_VELES_NPC_PRIEST","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_PRIEST","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당신이... 벌레 아저씨?","JPN":"あなたが……デレおじさん？","ENG":"Are you... Mr. Belly?","TWN":"你是……蟲子大叔？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DEMON_VELES_NPC_PRIEST","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_PRIEST","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DEMON_VELES_NPC_PRIEST","text":{"KOREA":"하하, 사소한 오해가 있었나 보군요.","JPN":"はは、少々誤解があったようですね。","ENG":"Haha, it seems there's been a small misunderstanding.","TWN":"哈哈，看來有點小誤會。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_PRIEST","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"저는 벨레스라고 합니다. 황금나무를 모시는 사제장으로서, 도시 아나필리스의 크고 작은 일들을 거들고 있죠.","JPN":"私はヴェレスと申します。黄金の木に仕える司祭長として、この街、アナピリスの様々な仕事を手伝っています。","ENG":"My name is Veles. As the Krivi, the high priest who serves the Golden Tree, I help oversee the affairs of the city of Anapilis.","TWN":"我叫貝雷斯。身為黃金樹的祭司長，協助阿納菲莉絲城市的大大小小事務。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"벨레스 씨... 였군요.","JPN":"ヴェレスさん……だったんですね。","ENG":"Veles... I see.","TWN":"原來是……貝雷斯啊。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하긴, 사람 이름이 벌레일 리가 없는데... 저도 참 경황이 없네요.","JPN":"確かに、人の名前が「デレ」なわけないですよね……どうかしていました。","ENG":"Well, I suppose no one would actually be named \\"Belly\\"... I must be a bit out of sorts.","TWN":"也對，人的名字怎麼會叫蟲子嘛……我也真是太慌亂了。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"이해합니다. 클라라도 아직 낙원에 한창 적응해나가는 시기니까요.","JPN":"分かります。クララもまだ楽園に適応している最中ですから。","ENG":"Understandable. Clara is still adjusting to life in the Promised Land.","TWN":"我理解。克拉拉還在適應樂園的生活呢。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"클라라... 그 아이 이름이구나.","JPN":"クララ……あの子のことですね。","ENG":"Clara... So that's the girl's name.","TWN":"克拉拉……原來那孩子叫這個名字啊。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"외지 사람이 이곳에 오게 되는 일은 그리 흔치 않답니다.","JPN":"外の人がここに来ることは滅多にないのです。","ENG":"It's not very common for outsiders to arrive here.","TWN":"外地人來到這裡的事並不常見。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"황금나무의 의지가 당신을 이곳으로 인도한 셈이죠.","JPN":"黄金の木の意志が、あなたをここに導いたのでしょう。","ENG":"It seems the will of the Golden Tree has guided you to this place.","TWN":"黃金樹的意志將你引導至此。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"황금나무라면... 저 커다란 나무를 말하는 건가?","JPN":"黄金の木って……あの大きな木のこと？","ENG":"The Golden Tree... Does he mean that enormous tree?","TWN":"黃金樹……是指那棵大樹嗎？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"한 번도 본 적 없는 풍경이지만, 왠지 낯설지가 않아.","JPN":"初めて見る景色だけど、なんだか懐かしい。","ENG":"I've never seen scenery like this before, and yet it somehow doesn't feel unfamiliar.","TWN":"雖然我從未見過，但總覺得不陌生。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"아나필리스라는 도시는 위치가 정확히 어떻게 되죠?","JPN":"アナピリスという街は、どこに位置しているのですか？","ENG":"Where exactly is the city called Anapilis located?","TWN":"阿納菲莉絲這個城市的具體位置在哪裡呢？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"아나필리스는 그 어디와도 이어져 있지 않습니다.","JPN":"アナピリスは他のどことも繋がっていません。","ENG":"Anapilis is not connected to anywhere.","TWN":"阿納菲莉絲不與任何地方相連。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그러니 장소를 특정 하는 것은 무의미하답니다.","JPN":"ですので、場所を特定することは意味のないことです。","ENG":"Which makes specifying its location rather meaningless.","TWN":"所以定位毫無意義。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하하... 수수께끼도 좋은데 진짜 정보를 들려주시면 안 될까요?","JPN":"はは……なぞなぞもいいですが、本当の情報を聞かせてもらえませんか？","ENG":"Haha... Riddles are nice and all, but could you tell me something real instead?","TWN":"哈哈……謎語很有趣，但能給我點真正的情報嗎？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"어쩌다 보니 신세를 지게 됐지만, 계속 여기 머물 순 없어서요.","JPN":"たまたまお世話になってはいますけど、ずっとここにいるわけにもいかないので。","ENG":"I ended up relying on your kindness, but I can't stay here forever.","TWN":"雖然因緣際會欠了你們人情，但我不能一直待在這裡。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"달리, 이곳을 떠나야 할 용무라도 있습니까?","JPN":"ここを離れなければいけない用事でもあるのですか？","ENG":"Is there some reason you must leave this place?","TWN":"你還有其他事需要離開這裡嗎？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그건...","JPN":"それは……","ENG":"That's...","TWN":"那個……"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"어...?","JPN":"あれ……？","ENG":"Huh...?","TWN":"嗯……？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"타기리온을 막으려던 것까진 기억이 나는데...","JPN":"タギリオンを止めようとしたことまでは覚えているのに……","ENG":"I remember trying to stop Thagirion...","TWN":"我有阻止塔基里翁的記憶……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...그 뒤의 일은 왜 이렇게 어렴풋하지?","JPN":"……その後の事はどうしてこんなにぼんやりしてるんだろう？","ENG":"...But why is everything after that so hazy?","TWN":"……但之後發生的事情怎麼這麼模糊？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"지금까지 있었던 기억이 마치... 전부 꿈이었던 것처럼 아득해.","JPN":"今までの記憶がまるで……全部夢の中で起こったことのようにはっきりしない。","ENG":"Everything that's happened up until now feels like... it was all just a dream.","TWN":"到現在的記憶……都好像是作夢一樣。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};